import { describe, expect, it } from 'vitest';
import {
  parseRtl433JsonLine,
  summarizeRtl433Events,
} from './rtl433';

describe('rtl433 jsonl parsing', () => {
  it('parses model/frequency/id/channel from common payload', () => {
    const ev = parseRtl433JsonLine(
      JSON.stringify({
        time: '2026-05-06 07:00:01',
        model: 'Acurite-Tower',
        id: 1234,
        channel: 'A',
        freq: 433920000,
        temperature_C: 21.7,
      }),
    );
    expect(ev).not.toBeNull();
    expect(ev?.model).toBe('Acurite-Tower');
    expect(ev?.id).toBe('1234');
    expect(ev?.channel).toBe('A');
    expect(ev?.frequencyHz).toBe(433920000);
  });

  it('ignores non-json and empty lines', () => {
    expect(parseRtl433JsonLine('')).toBeNull();
    expect(parseRtl433JsonLine('not-json')).toBeNull();
  });

  it('summarizes models and rounded MHz bins', () => {
    const events = [
      parseRtl433JsonLine('{"model":"m1","freq":433920000}')!,
      parseRtl433JsonLine('{"model":"m1","freq":433910000}')!,
      parseRtl433JsonLine('{"model":"m2","freq":915000000}')!,
    ];
    const s = summarizeRtl433Events(events);
    expect(s.count).toBe(3);
    expect(s.byModel['m1']).toBe(2);
    expect(s.byModel['m2']).toBe(1);
    expect(s.byRoundedFreqMHz['433.920']).toBe(1);
    expect(s.byRoundedFreqMHz['433.910']).toBe(1);
    expect(s.byRoundedFreqMHz['915.000']).toBe(1);
  });
});
